from dataclasses import dataclass

@dataclass
class DebtHealthSignal:
    s1_open: int               # S1 items not in a sprint
    s2_open: int               # S2 items not yet scheduled this quarter
    debt_growing: bool         # items opened > items closed last quarter
    last_incident_root_cause: str | None  # "debt" if last P1 caused by known debt item

    def recommended_allocation_pct(self) -> int:
        if self.s1_open > 0 or self.last_incident_root_cause == "debt":
            return 35   # S1 items must clear before next release
        if self.debt_growing:
            return 25   # debt compounding — increase repayment rate
        if self.s2_open > 10:
            return 20   # above-normal S2 backlog
        return 15       # healthy steady state

signal = DebtHealthSignal(
    s1_open=2,
    s2_open=6,
    debt_growing=False,
    last_incident_root_cause="debt",
)
print(f"Recommended allocation: {signal.recommended_allocation_pct()}%")
# → 35% because S1 items are open

from dataclasses import dataclass

@dataclass
class SprintCapacity:
    team_size: int
    sprint_days: int              # typically 10 (2-week sprint)
    pto_days: int                 # total PTO across team this sprint
    ceremony_overhead_pct: float  # planning + retro + review + standups (typically 15–20%)
    on_call_engineers: int        # engineers on rotation who lose ~30% capacity

    @property
    def raw_days(self) -> float:
        return self.team_size * self.sprint_days

    @property
    def available_days(self) -> float:
        raw = self.raw_days - self.pto_days
        ceremony_cost = raw * self.ceremony_overhead_pct
        oncall_cost = self.on_call_engineers * self.sprint_days * 0.30
        return raw - ceremony_cost - oncall_cost

    @property
    def debt_budget_days(self, allocation_pct: float = 0.15) -> float:
        return self.available_days * allocation_pct

capacity = SprintCapacity(
    team_size=6,
    sprint_days=10,
    pto_days=3,
    ceremony_overhead_pct=0.18,
    on_call_engineers=1,
)
print(f"Available: {capacity.available_days:.1f} days")
print(f"Debt budget (15%): {capacity.available_days * 0.15:.1f} days")
print(f"Debt budget (20%): {capacity.available_days * 0.20:.1f} days")

def select_sprint_debt_items(
    register: list[dict],
    budget_days: float,
    sprint_id: str,
) -> tuple[list[dict], float]:
    """
    Selects debt items for a sprint. Returns (selected_items, remaining_budget).
    Priority: S1 all in → S2 by effort/interest → S3 quick wins if budget remains.
    """
    interest_value = {"critical": 4, "high": 3, "medium": 2, "low": 1}
    severity_order = {"S1": 0, "S2": 1, "S3": 2, "S4": 3}

    unscheduled = [
        item for item in register
        if item.get("status") == "open" and not item.get("sprint")
    ]

    # Sort: S1 first, then by interest rate desc, then effort asc (quick wins)
    sorted_items = sorted(
        unscheduled,
        key=lambda x: (
            severity_order[x["severity"]],
            -interest_value[x["interest_rate"]],
            x["effort_days"],
        )
    )

    selected, remaining = [], budget_days
    for item in sorted_items:
        if remaining <= 0:
            break
        # S1 items always included even if they blow the budget slightly
        if item["severity"] == "S1" or item["effort_days"] <= remaining:
            selected.append({**item, "sprint": sprint_id})
            remaining -= item["effort_days"]

    return selected, max(0, remaining)

